export const getGetDueReviewsUrl = (params?: GetDueReviewsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/review/due?${stringifiedParams}` : `/api/review/due`
}

/**
 * @summary Get words due for spaced repetition review
 */
export const getDueReviews = async (params?: GetDueReviewsParams, options?: RequestInit): Promise<ReviewSession> => {

  return customFetch<ReviewSession>(getGetDueReviewsUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





export const getGetDueReviewsQueryKey = (params?: GetDueReviewsParams,) => {
    return [
    `/api/review/due`, ...(params ? [params] : [])
    ] as const;
    }


export const getGetDueReviewsQueryOptions = <TData = Awaited<ReturnType<typeof getDueReviews>>, TError = ErrorType<unknown>>(params?: GetDueReviewsParams, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getDueReviews>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getGetDueReviewsQueryKey(params);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof getDueReviews>>> = ({ signal }) => getDueReviews(params, { signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof getDueReviews>>, TError, TData> & { queryKey: QueryKey }
}

export type GetDueReviewsQueryResult = NonNullable<Awaited<ReturnType<typeof getDueReviews>>>
export type GetDueReviewsQueryError = ErrorType<unknown>


